import { NextRequest, NextResponse } from 'next/server';
import ExcelJS from 'exceljs';
import path from 'path';
import fs from 'fs';

const FILE_PATH = path.join(process.cwd(), 'leads.xlsx');

const HEADERS = [
  'Timestamp',
  'Full Name',
  'Email',
  'Phone',
  'Program',
  'Destination',
  'Message',
];

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const { name, email, phone, program, destination, message } = body;

    if (!name || !email || !phone || !program || !destination) {
      return NextResponse.json(
        { error: 'Missing required fields' },
        { status: 400 }
      );
    }

    const workbook = new ExcelJS.Workbook();

    if (fs.existsSync(FILE_PATH)) {
      // Load the existing workbook
      await workbook.xlsx.readFile(FILE_PATH);
    }

    // Get or create the "Leads" sheet
    let worksheet = workbook.getWorksheet('Leads');
    if (!worksheet) {
      worksheet = workbook.addWorksheet('Leads');

      // Add header row with styling
      const headerRow = worksheet.addRow(HEADERS);
      headerRow.eachCell((cell) => {
        cell.font = { bold: true, color: { argb: 'FFFFFFFF' } };
        cell.fill = {
          type: 'pattern',
          pattern: 'solid',
          fgColor: { argb: 'FF1E3A5F' },
        };
        cell.alignment = { vertical: 'middle', horizontal: 'center' };
        cell.border = {
          top: { style: 'thin' },
          left: { style: 'thin' },
          bottom: { style: 'thin' },
          right: { style: 'thin' },
        };
      });

      // Set column widths
      worksheet.columns = [
        { key: 'timestamp', width: 22 },
        { key: 'name', width: 25 },
        { key: 'email', width: 30 },
        { key: 'phone', width: 18 },
        { key: 'program', width: 18 },
        { key: 'destination', width: 20 },
        { key: 'message', width: 40 },
      ];
    }

    // Append data row
    const timestamp = new Date().toLocaleString('en-IN', {
      timeZone: 'Asia/Kolkata',
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    });

    worksheet.addRow([
      timestamp,
      name,
      email,
      phone,
      program,
      destination,
      message || '',
    ]);

    await workbook.xlsx.writeFile(FILE_PATH);

    return NextResponse.json({ success: true }, { status: 200 });
  } catch (error) {
    console.error('[submit-lead] Error:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}
